import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as e,e as l}from"./app-01aedd85.js";const r={},n=l(`<h1 id="线上-rag-系统零停机重建向量库" tabindex="-1"><a class="header-anchor" href="#线上-rag-系统零停机重建向量库" aria-hidden="true">#</a> 线上 RAG 系统零停机重建向量库</h1><p>线上RAG系统<strong>绝对不能直接删除/覆盖正在使用的向量库</strong>，否则会导致服务报错、查询失败、业务中断。核心思路是：<strong>双库切换 + 流量无缝迁移</strong>，全程不影响线上服务。</p><p>我给你一套<strong>生产环境可直接落地</strong>的标准方案，步骤清晰、无风险、零停机。</p><h2 id="核心原理" tabindex="-1"><a class="header-anchor" href="#核心原理" aria-hidden="true">#</a> 核心原理</h2><ol><li><strong>线上始终有一个可用的「活跃向量库」</strong> 提供服务</li><li><strong>后台静默重建一个「新向量库」</strong></li><li>重建完成后，<strong>原子切换配置/路由</strong>，让流量切到新库</li><li>验证无误后，再删除旧库（安全兜底）</li></ol><h2 id="一、准备工作-必须先做" tabindex="-1"><a class="header-anchor" href="#一、准备工作-必须先做" aria-hidden="true">#</a> 一、准备工作（必须先做）</h2><ul><li><p><strong>给向量库加「版本/别名标识」</strong></p></li><li><p>不要用固定名字（如 <code>rag_db</code>），改用带版本/时间戳的名字：</p><ul><li><p>线上在用：<code>rag_v20260301</code></p></li><li><p>重建新库：<code>rag_v20260327</code></p></li></ul></li><li><p><strong>准备独立的重建任务</strong>：使用celery 异步任务</p></li><li></li></ul><h2 id="二、零停机重建完整步骤-最安全" tabindex="-1"><a class="header-anchor" href="#二、零停机重建完整步骤-最安全" aria-hidden="true">#</a> 二、零停机重建完整步骤（最安全）</h2><h3 id="步骤1-锁定当前线上活跃库-记录名称" tabindex="-1"><a class="header-anchor" href="#步骤1-锁定当前线上活跃库-记录名称" aria-hidden="true">#</a> 步骤1：锁定当前线上活跃库（记录名称）</h3><p>先确认线上正在用哪个向量库/集合，例如：</p><div class="language-Plain line-numbers-mode" data-ext="Plain"><pre class="language-Plain"><code>当前活跃库：rag_v1
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>服务配置指向这个库，全程不动。</strong></p><h3 id="步骤2-后台静默创建全新向量库" tabindex="-1"><a class="header-anchor" href="#步骤2-后台静默创建全新向量库" aria-hidden="true">#</a> 步骤2：后台静默创建全新向量库</h3><ul><li>创建新库：<code>rag_v2</code></li><li>加载全部原始文档</li><li>重新分块、向量化、批量插入</li><li>建立索引（IVF_FLAT / HNSW 等）</li></ul><p><strong>关键点</strong>：</p><ul><li>这个过程<strong>完全离线</strong>，不影响线上流量</li><li>可以做校验：数据条数、向量维度、索引状态</li></ul><h3 id="步骤3-新库预热-功能验证" tabindex="-1"><a class="header-anchor" href="#步骤3-新库预热-功能验证" aria-hidden="true">#</a> 步骤3：新库预热 &amp; 功能验证</h3><p>新库建好后不要立刻切换，先做验证：</p><ol><li>用测试接口查询新库，确保召回正常</li><li>检查RAG回答准确性</li><li>检查QPS、延迟、内存占用是否正常</li></ol><h3 id="步骤4-原子切换-零停机核心" tabindex="-1"><a class="header-anchor" href="#步骤4-原子切换-零停机核心" aria-hidden="true">#</a> 步骤4：原子切换（零停机核心）</h3><p>切换方式有 3 种，<strong>推荐优先级从高到低</strong>：</p><h4 id="方法1-使用向量库官方「别名-别名路由」-最稳" tabindex="-1"><a class="header-anchor" href="#方法1-使用向量库官方「别名-别名路由」-最稳" aria-hidden="true">#</a> 方法1：使用向量库官方「别名/别名路由」（最稳）</h4><p>几乎所有向量库都支持 <strong>别名 Alias</strong>：</p><ul><li>给线上服务配置别名：<code>rag_active</code></li><li>别名指向旧库：<code>rag_v1</code></li><li>重建完成后，<strong>一条命令把别名指向新库</strong> <strong><code>rag_v2</code></strong></li><li>切换是<strong>原子操作</strong>，毫秒级生效，无断服</li></ul><p>示例（Milvus）：</p><div class="language-Python line-numbers-mode" data-ext="Python"><pre class="language-Python"><code>utility.create_alias(collection_name=&quot;rag_v1&quot;, alias=&quot;rag_active&quot;)
utility.alter_alias(collection_name=&quot;rag_v2&quot;, alias=&quot;rag_active&quot;)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="方法2-服务优雅重启-兜底方案" tabindex="-1"><a class="header-anchor" href="#方法2-服务优雅重启-兜底方案" aria-hidden="true">#</a> 方法2：服务优雅重启（兜底方案）</h4><p>如果没有别名/配置中心：</p><ol><li>准备新版本服务，指向新库</li><li>滚动发布（先起新实例 → 流量切过去 → 再停旧实例）</li><li>Kubernetes / 云服务 都支持<strong>滚动更新</strong></li></ol><h3 id="步骤5-观察监控-确认稳定" tabindex="-1"><a class="header-anchor" href="#步骤5-观察监控-确认稳定" aria-hidden="true">#</a> 步骤5：观察监控 + 确认稳定</h3><p>切换后观察 5~10 分钟：</p><ul><li>查询成功率</li><li>响应延迟</li><li>错误率</li><li>RAG 回答准确率</li></ul><h3 id="步骤6-安全删除旧向量库-不要急删" tabindex="-1"><a class="header-anchor" href="#步骤6-安全删除旧向量库-不要急删" aria-hidden="true">#</a> 步骤6：安全删除旧向量库（不要急删）</h3><p>确认新库稳定运行 <strong>至少30分钟</strong> 后，再删除旧库：</p><div class="language-Plain line-numbers-mode" data-ext="Plain"><pre class="language-Plain"><code>rag_v1 # 旧库，可删除
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="三、超大数据量优化-防止重建太慢" tabindex="-1"><a class="header-anchor" href="#三、超大数据量优化-防止重建太慢" aria-hidden="true">#</a> 三、超大数据量优化（防止重建太慢）</h2><p>如果向量库<strong>上亿条、TB级</strong>，直接全量重建太慢，用这些优化：</p><h3 id="_1-增量重建-全量重建结合" tabindex="-1"><a class="header-anchor" href="#_1-增量重建-全量重建结合" aria-hidden="true">#</a> 1. 增量重建 + 全量重建结合</h3><ul><li>日常用<strong>增量更新</strong>（只更新变更文档）</li><li>每周/每月做一次<strong>全量重建</strong>（本方案）</li></ul><h3 id="_2-批量并行插入" tabindex="-1"><a class="header-anchor" href="#_2-批量并行插入" aria-hidden="true">#</a> 2. 批量并行插入</h3><ul><li>开启多线程/多进程导入</li><li>向量库关闭实时索引，导入完成后再批量建索引（速度提升10~100倍）</li></ul><h3 id="_3-分离服务资源" tabindex="-1"><a class="header-anchor" href="#_3-分离服务资源" aria-hidden="true">#</a> 3. 分离服务资源</h3><ul><li>重建用<strong>独立机器/独立队列</strong></li><li>不占用线上RAG服务CPU/GPU/内存</li></ul><h2 id="四、严禁操作-避坑指南" tabindex="-1"><a class="header-anchor" href="#四、严禁操作-避坑指南" aria-hidden="true">#</a> 四、严禁操作（避坑指南）</h2><ol><li>❌ 不要直接删除线上正在使用的向量库</li><li>❌ 不要直接往线上库覆盖写入</li><li>❌ 不要在高峰期重建/切换</li><li>❌ 不要不验证就切流量</li></ol><h2 id="五、极简流程图-一眼看懂" tabindex="-1"><a class="header-anchor" href="#五、极简流程图-一眼看懂" aria-hidden="true">#</a> 五、极简流程图（一眼看懂）</h2><div class="language-Plain line-numbers-mode" data-ext="Plain"><pre class="language-Plain"><code>线上服务 → 旧向量库（正常运行）
      ↓
后台创建 → 新向量库（静默重建）
      ↓
新库验证通过
      ↓
别名/配置 原子切换 → 流量切到新库
      ↓
监控稳定 → 删除旧库
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="六、生产环境推荐架构" tabindex="-1"><a class="header-anchor" href="#六、生产环境推荐架构" aria-hidden="true">#</a> 六、生产环境推荐架构</h2><div class="language-Plain line-numbers-mode" data-ext="Plain"><pre class="language-Plain"><code>[用户请求] → [RAG服务] → [向量库别名] → [当前活跃库]
                                          ↓
                                 新库就绪 → 原子切换
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h3><ol><li>核心方案：<strong>双库共存 + 别名原子切换</strong>，真正零停机</li><li>全程线上服务不中断、不报错、无感知</li><li>大库优化：批量导入、离线重建、关闭实时索引</li><li>安全底线：先验证、再切换、最后删旧库</li></ol>`,51),d=[n];function s(t,o){return a(),e("div",null,d)}const u=i(r,[["render",s],["__file","14、线上RAG系统设计.html.vue"]]);export{u as default};
